function calculateRisk(inputs) {
  const { age, vaccination_status_score, chronic_conditions_count, immune_suppressant_meds, living_environment_score, hygiene_compliance_score, local_case_prevalence_index, stress_level_score } = inputs;

  let score = 0;

  // 1. Age Factor (Weight: up to 20 points)
  if (age < 5 || age >= 65) {
    score += 18; // Higher risk for very young and elderly
  } else if (age >= 55) {
    score += 10;
  } else if (age < 18) {
    score += 5; // Moderate risk for school-aged
  }

  // 2. Vaccination Status (Weight: -15 to +5 points)
  // Lower score is better, so subtract more for higher vaccination_status_score
  // Max 5 points for no vaccination (score 1), min -15 for score 5
  score += (6 - vaccination_status_score) * 4 - 5; // Ranges from (5*4-5=15) to (1*4-5=-1)
  score = Math.max(score, -15); // Cap to prevent overly negative scores for excellent vaccination

  // 3. Chronic Conditions (Weight: up to 20 points)
  score += Math.min(chronic_conditions_count, 5) * 4; // Each condition adds 4 points, capped at 5 conditions

  // 4. Immune Suppressant Medications (Weight: up to 25 points)
  if (immune_suppressant_meds === 1) {
    score += 25;
  }

  // 5. Living/Working Environment Exposure (Weight: up to 15 points)
  score += (living_environment_score - 1) * 3.5; // Ranges from 0 to 4 * 3.5 = 14

  // 6. Hygiene Compliance (Weight: -10 to +10 points)
  // Lower score is better, so subtract more for higher hygiene_compliance_score
  score += (6 - hygiene_compliance_score) * 2 - 5; // Ranges from (5*2-5=5) to (1*2-5=-3)

  // 7. Local Case Prevalence Index (Weight: up to 15 points)
  score += (local_case_prevalence_index / 10) * 15; // Directly proportional to prevalence, max 15

  // 8. Stress Level (Weight: up to 10 points)
  score += (stress_level_score - 1) * 2.5; // Ranges from 0 to 4 * 2.5 = 10

  // Ensure score is within a reasonable range (0-100 for normalization)
  score = Math.round(Math.max(0, Math.min(score, 100)));

  let risk_category;
  let recommendation_level;

  if (score <= 25) {
    risk_category = 'Low Risk';
    recommendation_level = 'Maintain current preventive practices. Stay informed about local health alerts.';
  } else if (score <= 50) {
    risk_category = 'Moderate Risk';
    recommendation_level = 'Consider reinforcing hygiene, optimizing diet, and staying well-rested. Consult healthcare provider if concerned.';
  } else if (score <= 75) {
    risk_category = 'High Risk';
    recommendation_level = 'Implement enhanced preventive measures. Consult your doctor for personalized advice. Be vigilant about symptoms.';
  } else {
    risk_category = 'Very High Risk';
    recommendation_level = 'Seek immediate medical advice for comprehensive risk management. Strictly adhere to all preventive guidelines and monitor health closely.';
  }

  return {
    risk_score: score,
    risk_category: risk_category,
    recommendation_level: recommendation_level
  };
}
